import{_ as e,c as o,o as a,a1 as i}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"Mobile Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/quickstart/index.md","filePath":"docs/mobile/quickstart/index.md"}'),n={name:"docs/mobile/quickstart/index.md"};function r(s,t,l,d,c,h){return a(),o("div",null,t[0]||(t[0]=[i('<h1 id="mobile-quick-start" tabindex="-1">Mobile Quick Start <a class="header-anchor" href="#mobile-quick-start" aria-label="Permalink to &quot;Mobile Quick Start&quot;">​</a></h1><p>Get up and running with Chaterm on iOS or Android in five steps.</p><h2 id="step-1-install-the-app" tabindex="-1">Step 1: Install the App <a class="header-anchor" href="#step-1-install-the-app" aria-label="Permalink to &quot;Step 1: Install the App&quot;">​</a></h2><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><ol><li>Open the <a href="https://apps.apple.com/app/6754307456" target="_blank" rel="noreferrer">App Store</a>.</li><li>Search for <strong>Chaterm</strong> and install it.</li><li>Complete the permission prompts when you launch it for the first time.</li></ol><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><ol><li>Open <a href="https://play.google.com/store/apps/details?id=com.intsig.chaterm.global" target="_blank" rel="noreferrer">Google Play</a>.</li><li>Search for <strong>Chaterm</strong> and install it.</li><li>Complete the permission prompts when you launch it for the first time.</li></ol><div class="tip custom-block"><p class="custom-block-title">Sign In Early</p><p>If you want data sync and full AI features, sign in before you start using the app.</p></div><h2 id="step-2-sign-in" tabindex="-1">Step 2: Sign In <a class="header-anchor" href="#step-2-sign-in" aria-label="Permalink to &quot;Step 2: Sign In&quot;">​</a></h2><p>Chaterm mobile supports signing in now or browsing first and finishing sign-in later. Available methods:</p><ul><li><strong>Email</strong> -- receive a verification code to sign in</li><li><strong>Username and password</strong> -- use your existing credentials</li><li><strong>Third-party</strong> -- sign in with Google, GitHub, or Apple, depending on availability in the app</li></ul><h2 id="step-3-add-your-first-host" tabindex="-1">Step 3: Add Your First Host <a class="header-anchor" href="#step-3-add-your-first-host" aria-label="Permalink to &quot;Step 3: Add Your First Host&quot;">​</a></h2><ol><li>Open the <strong>Assets</strong> page.</li><li>Enter <strong>Direct Connections</strong> and tap the <strong>+</strong> button in the lower-right corner.</li><li>Choose <strong>New</strong>.</li><li>Fill in the host label, IP address, port, username, and other details.</li><li>Select <strong>password authentication</strong> or <strong>key authentication</strong>.</li><li>Tap <strong>Save</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Desktop Sync</p><p>If you have enabled data sync on desktop, your asset data is encrypted and synced to mobile automatically. See <a href="/docs/mobile/assets/">Asset Management</a> for more details.</p></div><h2 id="step-4-open-an-ssh-connection" tabindex="-1">Step 4: Open an SSH Connection <a class="header-anchor" href="#step-4-open-an-ssh-connection" aria-label="Permalink to &quot;Step 4: Open an SSH Connection&quot;">​</a></h2><ol><li>Tap the target host card in the asset list.</li><li>Chaterm automatically creates the SSH connection.</li><li>After the connection succeeds, you enter the terminal screen.</li></ol><p>Common actions:</p><ul><li><strong>Tap</strong> a host card to connect directly.</li><li><strong>Long-press</strong> a card to edit, favorite, or delete it.</li><li><strong>Search</strong> to quickly filter by host name, IP, username, or group.</li></ul><h2 id="step-5-start-using-ai" tabindex="-1">Step 5: Start Using AI <a class="header-anchor" href="#step-5-start-using-ai" aria-label="Permalink to &quot;Step 5: Start Using AI&quot;">​</a></h2><p>Mobile provides two main interaction modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Term</strong></td><td>Directly runs the command you enter</td></tr><tr><td><strong>Chat</strong></td><td>AI understands your request and suggests commands or actions</td></tr></tbody></table><p>Basic flow:</p><ol><li>Open the AI dialog page.</li><li>Connect to a target host or select a model.</li><li>Switch modes from the selector at the bottom of the input box.</li><li>Enter a question or command, or use voice input.</li><li>Review the execution result or the AI response.</li></ol><p>For more details, see <a href="/docs/mobile/ai-agent/">AI Dialog</a>.</p><h2 id="recommended-first-run" tabindex="-1">Recommended First Run <a class="header-anchor" href="#recommended-first-run" aria-label="Permalink to &quot;Recommended First Run&quot;">​</a></h2><ol><li>Add a test host.</li><li>Start one SSH session.</li><li>Run <code>pwd</code> or <code>uname -a</code> in <strong>Term</strong> mode.</li><li>Switch to <strong>Chat</strong> mode and ask a Linux command question.</li><li>Open <strong>Profile</strong> and configure theme, language, and AI preferences.</li></ol>',26)]))}const m=e(n,[["render",r]]);export{u as __pageData,m as default};
